// Precomputation for Mobius function up to V_MAX
const V_MAX = 50000;
const mu = new Array(V_MAX + 1).fill(0);
const lp = new Array(V_MAX + 1).fill(0); // least prime factor
const primes = [];

function sieve() {
    mu[1] = 1;
    for (let i = 2; i <= V_MAX; i++) {
        if (lp[i] === 0) {
            lp[i] = i;
            primes.push(i);
            mu[i] = -1;
        }
        for (const p of primes) {
            if (p > lp[i] || i * p > V_MAX) break;
            lp[i * p] = p;
            if (p === lp[i]) {
                mu[i * p] = 0; // p^2 divides i*p
            } else {
                mu[i * p] = -mu[i];
            }
        }
    }
}

sieve();

function getDivisors(n) {
    const divisors = new Set();
    for (let i = 1; i * i <= n; i++) {
        if (n % i === 0) {
            divisors.add(i);
            divisors.add(n / i);
        }
    }
    return Array.from(divisors);
}

/**
 * Calculates the binomial coefficient C(n, 2) = n * (n - 1) / 2.
 * @param {number} n
 * @returns {number}
 */
function combinations2(n) {
    if (n < 2) return 0;
    // Since we are dealing with counts, the result fits within standard JS number type (up to 2^53)
    return n * (n - 1) / 2;
}


function solve(nums, p, queries) {
    const n = nums.length;

    // CountMul[k]: number of elements in nums divisible by k
    const CountMul = new Array(V_MAX + 1).fill(0);

    // Initialize CountMul
    for (const x of nums) {
        const divisors = getDivisors(x);
        for (const d of divisors) {
            if (d <= V_MAX) {
                CountMul[d]++;
            }
        }
    }

    let goodSubsequenceCount = 0;
    let queryCount = 0;

    /**
     * Checks if a good subsequence exists in the current nums array.
     * @returns {boolean}
     */
    const checkExistence = () => {
        // Case 1: Singleton subsequence check (Only relevant if n=2)
        if (n === 2) {
            return nums[0] === p || nums[1] === p;
        }

        // Case 2: n > 2. Check for a pair GCD = p.
        // Sum over k: mu(k) * C(CountMul[k*p], 2)
        // This counts pairs (x, y) such that gcd(x, y) = p.

        let pairCount = 0;
        const maxK = Math.floor(V_MAX / p);

        for (let k = 1; k <= maxK; k++) {
            const g = k * p;
            if (g > V_MAX) break;

            if (mu[k] !== 0) {
                const c = CountMul[g];
                const combinations = combinations2(c);

                if (mu[k] === 1) {
                    pairCount += combinations;
                } else { // mu[k] === -1
                    pairCount -= combinations;
                }
            }
        }

        // If pairCount > 0, there exists at least one pair {x, y} with gcd(x, y) = p.
        // Since n > 2, {x, y} is a good subsequence (length 2 < n).
        if (pairCount > 0) {
            return true;
        }

        // Case 3: Check if any single element is p (only necessary if n > 2, but it's covered by pairCount if we consider it an edge case)
        // Since n > 2, a single element {p} has length 1 < n, and GCD is p.
        if (CountMul[p] > 0) {
            return true;
        }

        return false;
    };


    for (const [ind, val] of queries) {
        const old_val = nums[ind];

        if (old_val === val) {
            // No change, just re-check
            if (checkExistence()) {
                queryCount++;
            }
            continue;
        }

        // Update CountMul based on old_val
        const oldDivisors = getDivisors(old_val);
        for (const d of oldDivisors) {
            if (d <= V_MAX) {
                CountMul[d]--;
            }
        }

        // Update nums and CountMul based on new_val
        nums[ind] = val;
        const newDivisors = getDivisors(val);
        for (const d of newDivisors) {
            if (d <= V_MAX) {
                CountMul[d]++;
            }
        }

        // Check existence after update
        if (checkExistence()) {
            queryCount++;
        }
    }

    return queryCount;
}

