// Precomputation for Mobius function up to V_MAX
const V_MAX = 50000;
const mu = new Array(V_MAX + 1).fill(0);
const lp = new Array(V_MAX + 1).fill(0); // least prime factor
const primes = [];

function sieve() {
    mu[1] = 1;
    for (let i = 2; i <= V_MAX; i++) {
        if (lp[i] === 0) {
            lp[i] = i;
            primes.push(i);
            mu[i] = -1;
