        for (const p of primes) {
            if (p > lp[i] || i * p > V_MAX) break;
            lp[i * p] = p;
            if (p === lp[i]) {
                mu[i * p] = 0; // p^2 divides i*p
            } else {
                mu[i * p] = -mu[i];
            }
        }
    }
