            const g = k * p;
            if (g > V_MAX) break;

            if (mu[k] !== 0) {
                const c = CountMul[g];
                const combinations = combinations2(c);

                if (mu[k] === 1) {
                    pairCount += combinations;
                } else { // mu[k] === -1
                    pairCount -= combinations;
                }
            }
        }

        // If pairCount > 0, there exists at least one pair {x, y} with gcd(x, y) = p.
        // Since n > 2, {x, y} is a good subsequence (length 2 < n).
        if (pairCount > 0) {
            return true;
        }

        // Case 3: Check if any single element is p (only necessary if n > 2, but it's covered by pairCount if we consider it an edge case)
        // Since n > 2, a single element {p} has length 1 < n, and GCD is p.
        if (CountMul[p] > 0) {
            return true;
        }

        return false;
    };


    for (const [ind, val] of queries) {
        const old_val = nums[ind];

        if (old_val === val) {
            // No change, just re-check
            if (checkExistence()) {
                queryCount++;
            }
            continue;
        }

        // Update CountMul based on old_val
        const oldDivisors = getDivisors(old_val);
        for (const d of oldDivisors) {
            if (d <= V_MAX) {
                CountMul[d]--;
            }
        }

        // Update nums and CountMul based on new_val
        nums[ind] = val;
        const newDivisors = getDivisors(val);
        for (const d of newDivisors) {
            if (d <= V_MAX) {
                CountMul[d]++;
            }
        }

        // Check existence after update
        if (checkExistence()) {
            queryCount++;
        }
    }

    return queryCount;
}
